"use client";

import * as React from "react";
import { OTPFieldPreview as BaseOTPField } from "@base-ui/react/otp-field";

import { cn } from "@/lib/utils";

import "./otp-field.css";

function OTPField({
  className,
  ...props
}: React.ComponentProps<typeof BaseOTPField.Root>) {
  return (
    <BaseOTPField.Root
      data-slot="otp-field"
      className={cn("flex items-center gap-2", className)}
      {...props}
    />
  );
}

function OTPFieldInput({
  className,
  variant = "default",
  ...props
}: React.ComponentProps<typeof BaseOTPField.Input> & {
  variant?: "default" | "elevated";
}) {
  return (
    <BaseOTPField.Input
      data-slot="otp-field-input"
      className={cn(
        // Base styling
        "flex h-10 w-10 items-center justify-center rounded-lg border bg-clip-padding text-center text-base font-medium sm:h-9 sm:w-9 md:text-sm",
        variant === "default" ? "bg-input" : "bg-input-elevated",
        // Selection
        "selection:bg-primary selection:text-primary-foreground",
        // Placeholder
        "placeholder:text-muted-foreground focus:placeholder:text-transparent",
        // :focus not data-[focused] — data-[focused] propagates to all inputs
        // in the group, not just the active one.
        "outline-0 outline-offset-0 outline-transparent transition-[outline-width,outline-offset,outline-color] duration-100 ease-out outline-solid",
        "focus:outline-ring/50 focus:outline-2 focus:outline-offset-2",
        // Invalid state
        "aria-invalid:outline-destructive/50 aria-invalid:outline-2 aria-invalid:outline-offset-2 aria-invalid:outline-solid",
        // Disabled state
        "data-[disabled]:pointer-events-none data-[disabled]:cursor-not-allowed data-[disabled]:opacity-60",
        className,
      )}
      {...props}
    />
  );
}

function OTPFieldSeparator({
  className,
  children,
  ...props
}: React.ComponentProps<typeof BaseOTPField.Separator>) {
  return (
    <BaseOTPField.Separator
      data-slot="otp-field-separator"
      className={cn("text-muted-foreground", className)}
      {...props}
    >
      {children ?? <SeparatorDash />}
    </BaseOTPField.Separator>
  );
}

function OTPFieldGroup({
  className,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="otp-field-group"
      className={cn("flex items-center gap-2", className)}
      {...props}
    />
  );
}

function SeparatorDash(props: React.ComponentProps<"svg">) {
  return (
    <svg
      aria-hidden="true"
      viewBox="0 0 8 2"
      width="8"
      height="2"
      fill="none"
      {...props}
    >
      <path
        d="M1 1H7"
        stroke="currentColor"
        strokeWidth="1.5"
        strokeLinecap="round"
      />
    </svg>
  );
}

export { OTPField, OTPFieldInput, OTPFieldSeparator, OTPFieldGroup };

"use client";

import * as React from "react";

export interface UseInvalidFeedbackOptions {
  /**
   * Duration in ms before the shake animation clears.
   * @default 400
   */
  duration?: number;
}

export interface UseInvalidFeedbackReturn {
  /**
   * Returns the invalid animation className for a given input index,
   * or `undefined` when no feedback is active. Merge with `cn()`.
   *
   * @example
   * ```tsx
   * <OTPFieldInput className={invalidFeedback.getInvalidClassName(index)} />
   * ```
   */
  getInvalidClassName: (index: number) => string | undefined;

  /**
   * Call in each input's `onFocus` to track which slot is active.
   *
   * @example
   * ```tsx
   * <OTPFieldInput onFocus={() => invalidFeedback.setFocusedIndex(index)} />
   * ```
   */
  setFocusedIndex: (index: number) => void;

  /**
   * Clears invalid feedback when the value changes.
   * Wire to OTPField's `onValueChange`.
   *
   * @example
   * ```tsx
   * <OTPField onValueChange={invalidFeedback.handleValueChange} />
   * ```
   */
  handleValueChange: () => void;

  /**
   * Triggers invalid feedback animation and status message.
   * Wire to OTPField's `onValueInvalid`.
   *
   * @example
   * ```tsx
   * <OTPField onValueInvalid={invalidFeedback.handleValueInvalid} />
   * ```
   */
  handleValueInvalid: (value: string) => void;

  /**
   * Screen reader status message. Render inside an `aria-live` region.
   *
   * @example
   * ```tsx
   * <span aria-live="polite" className="sr-only">
   *   {invalidFeedback.statusMessage}
   * </span>
   * ```
   */
  statusMessage: string;
}

const SHAKE_CLASS_A = "otp-field-shake-a focus:outline-destructive/80";
const SHAKE_CLASS_B = "otp-field-shake-b focus:outline-destructive/80";

/**
 * Hook that manages shake animation and screen reader feedback
 * for invalid OTP input.
 *
 * @example
 * ```tsx
 * const invalidFeedback = useInvalidFeedback();
 *
 * <OTPField
 *   length={6}
 *   validationType="none"
 *   normalizeValue={normalizeTierCode}
 *   onValueChange={invalidFeedback.handleValueChange}
 *   onValueInvalid={invalidFeedback.handleValueInvalid}
 * >
 *   {Array.from({ length: 6 }, (_, index) => (
 *     <OTPFieldInput
 *       key={index}
 *       className={invalidFeedback.getInvalidClassName(index)}
 *       onFocus={() => invalidFeedback.setFocusedIndex(index)}
 *     />
 *   ))}
 * </OTPField>
 * <span aria-live="polite" className="sr-only">
 *   {invalidFeedback.statusMessage}
 * </span>
 * ```
 */
export function useInvalidFeedback(
  options: UseInvalidFeedbackOptions = {},
): UseInvalidFeedbackReturn {
  const { duration = 400 } = options;

  const [focusedIndex, setFocusedIndex] = React.useState(0);
  const [invalidPulse, setInvalidPulse] = React.useState(0);
  const [statusMessage, setStatusMessage] = React.useState("");
  const invalidTimeoutRef = React.useRef<ReturnType<typeof setTimeout> | null>(
    null,
  );
  const skipClearOnNextValueChangeRef = React.useRef(false);

  React.useEffect(() => {
    return () => {
      if (invalidTimeoutRef.current != null) {
        clearTimeout(invalidTimeoutRef.current);
      }
    };
  }, []);

  function handleValueChange() {
    if (skipClearOnNextValueChangeRef.current) {
      skipClearOnNextValueChangeRef.current = false;
      return;
    }

    if (invalidTimeoutRef.current != null) {
      clearTimeout(invalidTimeoutRef.current);
      invalidTimeoutRef.current = null;
    }
    setInvalidPulse(0);
    setStatusMessage("");
  }

  function handleValueInvalid(value: string) {
    skipClearOnNextValueChangeRef.current = true;
    setInvalidPulse((current) => current + 1);
    setStatusMessage(`Unsupported characters were ignored from ${value}.`);

    if (invalidTimeoutRef.current != null) {
      clearTimeout(invalidTimeoutRef.current);
    }

    invalidTimeoutRef.current = setTimeout(() => {
      invalidTimeoutRef.current = null;
      setInvalidPulse(0);
    }, duration);
  }

  const activeInvalidIndex = invalidPulse > 0 ? focusedIndex : -1;
  const invalidClassName =
    invalidPulse === 0
      ? undefined
      : invalidPulse % 2 === 0
        ? SHAKE_CLASS_B
        : SHAKE_CLASS_A;

  const getInvalidClassName = React.useCallback(
    (index: number) =>
      activeInvalidIndex === index ? invalidClassName : undefined,
    [activeInvalidIndex, invalidClassName],
  );

  return {
    getInvalidClassName,
    setFocusedIndex,
    handleValueChange,
    handleValueInvalid,
    statusMessage,
  };
}

/* -------------------------------------------------------------------------------------------------
 * OTP field invalid-input shake animation.
 *
 * Paired identical keyframes. CSS animations don't restart when re-applied to
 * the same element with the same animation-name, so on each invalid OTP entry
 * we alternate between the two classes to force the browser to treat it as a
 * new animation and replay the shake. Keep both bodies in sync.
 * -------------------------------------------------------------------------------------------------*/

.otp-field-shake-a {
  animation: otp-field-shake-a 180ms ease-in-out;
}

.otp-field-shake-b {
  animation: otp-field-shake-b 180ms ease-in-out;
}

@keyframes otp-field-shake-a {
  0%,
  100% {
    transform: translateX(0);
  }
  25% {
    transform: translateX(-4px);
  }
  75% {
    transform: translateX(4px);
  }
}

@keyframes otp-field-shake-b {
  0%,
  100% {
    transform: translateX(0);
  }
  25% {
    transform: translateX(-4px);
  }
  75% {
    transform: translateX(4px);
  }
}

@media (prefers-reduced-motion: reduce) {
  .otp-field-shake-a,
  .otp-field-shake-b {
    animation: none;
  }
}
